4. Ensure the final code is complete, self-contained, and directly runnable.
5. Return ONLY the raw code. Do not include explanations, markdown backticks, or conversational text.

You are generating Scala code. You only need to generate the requested function. DO NOT generate the main method. DO NOT generate object/class.
The reference solution of that problem in Javascript is 
function solve(nums) {
    const n = nums.length;
    for (let p = 1; p <= n - 3; p++) {
        for (let q = p + 1; q <= n - 2; q++) {
            // Check first part: 0 to p is strictly increasing
            let valid = true;
            for (let i = 0; i < p; i++) {
                if (nums[i] >= nums[i + 1]) {
                    valid = false;
                    break;
                }
            }
            if (!valid) continue;

            // Check second part: p to q is strictly decreasing
            valid = true;
            for (let i = p; i < q; i++) {
                if (nums[i] <= nums[i + 1]) {
                    valid = false;
                    break;
                }
            }
            if (!valid) continue;

            // Check third part: q to end is strictly increasing
            valid = true;
            for (let i = q; i < n - 1; i++) {
                if (nums[i] >= nums[i + 1]) {
                    valid = false;
                    break;
                }
            }
            if (valid) {
                return true;
            }
        }
    }
    return false;
}

